mapper.select:
SELECT
    used_connections AS usedConnections,
    max_connections AS maxConnections
FROM session_metrics_agg_5m
WHERE instance_id = #{instanceId}
AND database_id = #{databaseId}
ORDER BY collected_at DESC
LIMIT 1;

SELECT
    COALESCE(SUM(deadlock_count), 0) AS deadlockCount
FROM session_metrics_agg_5m
WHERE instance_id = #{instanceId}
AND database_id = #{databaseId}
AND collected_at >= CURRENT_TIMESTAMP - INTERVAL '10 minutes'

SELECT
    collected_at AS collectedAt,
    deadlock_count AS deadlockCount
FROM session_metrics_agg_5m
WHERE instance_id = #{instanceId}
AND database_id = #{databaseId}
AND collected_at >= CURRENT_TIMESTAMP - INTERVAL '60 minutes'
ORDER BY collected_at;
